import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is one rep max?", a: "One rep max, or 1RM, is the maximum weight you can lift for one complete repetition with good form." },
  { q: "How do you calculate your 1RM?", a: "You can estimate 1RM from a submaximal set using formulas such as Epley, Brzycki, Lombardi, Mayhew, and O'Conner." },
  { q: "How accurate are 1RM formulas?", a: "They are estimates. Accuracy is usually best with lower rep sets, often around 2 to 8 reps." },
  { q: "How do you use 1RM percentages for training?", a: "Programs use percentages of 1RM to target strength, power, hypertrophy, technique, or endurance work." },
  { q: "How often should you test your one rep max?", a: "Many lifters test sparingly, such as every 8 to 16 weeks, or use rep-max estimates to reduce injury risk." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function OneRepMaxCalculator() {
  const [weight, setWeight] = useState(185);
  const [reps, setReps] = useState(5);
  const result = useMemo(() => {
    const epley = weight * (1 + reps / 30);
    const brzycki = weight * 36 / (37 - reps);
    const lombardi = weight * Math.pow(reps, 0.1);
    const mayhew = 100 * weight / (52.2 + 41.9 * Math.exp(-0.055 * reps));
    const oconner = weight * (1 + reps / 40);
    const avg = (epley + brzycki + lombardi + mayhew + oconner) / 5;
    return { epley, brzycki, lombardi, mayhew, oconner, avg };
  }, [weight, reps]);
  const rows = [[100, "1", "Max strength", "Test single"], [95, "2", "Near-max strength", "Heavy singles/doubles"], [90, "3-4", "Strength", "Heavy triples"], [85, "5-6", "Strength/hypertrophy", "Working sets"], [80, "7-8", "Hypertrophy", "Volume work"], [75, "9-10", "Hypertrophy", "Moderate sets"], [70, "11-12", "Technique/volume", "Practice reps"], [65, "13-15", "Muscular endurance", "Higher reps"], [60, "15+", "Warm-up/endurance", "Light work"]];
  return (
    <>
      <SEOHead title="Free One Rep Max Calculator Online - Calculate Your 1RM Instantly | CalcHive" description="Free online one rep max calculator. Calculate your estimated 1RM from any weight and reps using multiple formulas with training percentage breakdown instantly. 100% free, no signup required." canonical="/one-rep-max-calculator" keywords="free one rep max calculator, 1RM calculator free online, calculate one rep max free, bench press max calculator free, strength calculator free online" category="Health Calculators" breadcrumbName="Free One Rep Max Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free One Rep Max Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate your 1RM from weight and reps using multiple common strength formulas.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Weight lifted</label><input type="number" value={weight} onChange={(e) => setWeight(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Reps performed</label><input type="number" value={reps} onChange={(e) => setReps(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated 1RM</p><p className="text-5xl sm:text-6xl font-black text-white">{Math.round(result.avg)} lb</p></div><div className="grid grid-cols-1 sm:grid-cols-5 gap-3 mt-4">{[["Brzycki", result.brzycki], ["Epley", result.epley], ["Lombardi", result.lombardi], ["Mayhew", result.mayhew], ["O'Conner", result.oconner]].map(([label, value]) => <div key={String(label)} className="bg-accent/60 border border-border rounded-xl p-3 text-center"><p className="text-xs text-muted-foreground">{label}</p><p className="text-base font-extrabold">{Math.round(Number(value))} lb</p></div>)}</div></section><MedicalDisclaimer /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your One Rep Max for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a recent set taken close to failure. The calculator averages several formulas for a practical 1RM estimate.</p><h2 className="text-2xl font-bold">How to Use Your 1RM to Program Your Workouts</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Training Percentages of Your 1 Rep Max</caption><thead className="bg-muted/60"><tr>{["% of 1RM", "Reps You Can Do", "Training Goal", "Example Use"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={String(r[0])}>{r.map((c, i) => <td key={`${r[0]}-${i}`} className="py-2.5 px-3">{i === 0 ? `${c}%` : c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free 1RM Strength Calculator for Every Lifter</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/one-rep-max-calculator" headingLevel="h3" /></main>
    </>
  );
}


